import React,{useEffect}from 'react'
import {ReactNavbar} from "react-responsive-animate-navbar";

const Navbar = () => {
    const handleUserKeyPress = useCallback(event => {
        const { key, keyCode } = event;

        if (keyCode === 32 || (keyCode >= 65 && keyCode <= 90)) {
            setUserText(prevUserText => `${prevUserText}${key}`);
        }
    }, []);
    useEffect(()=>{
            var children = document.querySelectorAll(".styles_navLinks__38tON ul li");
            children.forEach(function (child) {
                // var a = document.getElementById(child);
                child.setAttribute("href", "#aboutme");
                child.addEventListener('click', (e) => {

                        window.scrollTo({
                            top: 400,
                            behavior: 'smooth',
                        })
                    }
                );
                // child.addEventListener('click', function(event){
                //     event.preventDefault();
                //     window.scrollTo(document.querySelector('#aboutme').offsetTop);
                //     // $('html, body').animate({
                //     //     scrollTop: $( $.attr(this, 'href') ).offset().top
                //     // }, 500);
                // });
                // child.href = "#aboutme";
                console.log(child);
                child.click();
            });




    },[]);
    return (
        <ReactNavbar
            color="rgb(25,100,50)"
            logo='logo-removebg-preview.png'
            menu={[
                { name: "HOME", to: "/" },
                { name: "ABOUT ME", to: "" },
                { name: "PROJECT", to: "" },
                { name: "CONTACT", to: "" },
            ]}
            social={[
                {
                    name: "Linkedin",
                    url: "https://www.linkedin.com/in/daniel-lee-00991085",
                    icon: ["fab", "linkedin-in"],
                },
                {
                    name: "Github",
                    url: "https://github.com/DMZnoo",
                    icon: ["fab", "github"],
                }
            ]}
        />
    )
};
export default Navbar;
